-				 */
-				if ((ring->me == me_id) &&
-				    (ring->pipe == pipe_id) &&
-				    (ring->queue == queue_id))
-					amdgpu_fence_process(ring);
-			}
-			break;
-		}
-	}
-
-	return 0;
+	return amdgpu_gfx_eop_irq(adev, source, entry);
 }

